changeSet.sql:
update account_selection_rule set code = 'CURRENCY' where code = 'currency';
update account_selection_rule set code = 'ORDER' where code = 'order';
update account_selection_rule set code = 'UNDEFINED' where code = 'undefined';

update payment_result set code = 'CANCELED' where code = 'canceled';
update payment_result set code = 'NOT_PAID' where code = 'notpaid';
update payment_result set code = 'PAID' where code = 'paid';

update payment set payment_link_type = 'AUTO' where payment_link_type is null and payment_link_type_id = any(select e.id from payment_link_type e where e.code = 'AUTO');
update payment set payment_link_type = 'MANUAL' where payment_link_type is null and payment_link_type_id = any(select e.id from payment_link_type e where e.code = 'MANUAL');
update payment set payment_link_type = 'REQUIREMENT' where payment_link_type is null and payment_link_type_id = any(select e.id from payment_link_type e where e.code = 'REQUIREMENT');

update payment set payment_result = 'CANCELED' where payment_result is null and payment_result_id = any(select e.id from payment_result e where e.code = 'CANCELED');
update payment set payment_result = 'NOT_PAID' where payment_result is null and payment_result_id = any(select e.id from payment_result e where e.code = 'NOT_PAID');
update payment set payment_result = 'PAID' where payment_result is null and payment_result_id = any(select e.id from payment_result e where e.code = 'PAID');

update requirement set payment_strategy_000_account_selection_rule = 'CURRENCY' where payment_strategy_000_account_selection_rule is null and payment_strategy_000_account_selection_rule_id = any(select e.id from account_selection_rule e where e.code = 'CURRENCY');
update requirement set payment_strategy_000_account_selection_rule = 'ORDER' where payment_strategy_000_account_selection_rule is null and payment_strategy_000_account_selection_rule_id = any(select e.id from account_selection_rule e where e.code = 'ORDER');
update requirement set payment_strategy_000_account_selection_rule = 'UNDEFINED' where payment_strategy_000_account_selection_rule is null and payment_strategy_000_account_selection_rule_id = any(select e.id from account_selection_rule e where e.code = 'UNDEFINED');

update requirement set state = 'CANCELED' where state is null and state_id = any(select e.id from requirement_status e where e.code = 'CANCELED');
update requirement set state = 'NONEXISTENT' where state is null and state_id = any(select e.id from requirement_status e where e.code = 'NONEXISTENT');
update requirement set state = 'PAID' where state is null and state_id = any(select e.id from requirement_status e where e.code = 'PAID');
update requirement set state = 'SUSPENDED' where state is null and state_id = any(select e.id from requirement_status e where e.code = 'SUSPENDED');
update requirement set state = 'WAIT' where state is null and state_id = any(select e.id from requirement_status e where e.code = 'WAIT');
update requirement set state = 'WRITTEN_OFF' where state is null and state_id = any(select e.id from requirement_status e where e.code = 'WRITTEN_OFF');

update requirements_group set group_payment_strategy = 'CONDITIONAL' where group_payment_strategy is null and group_payment_strategy_id = any(select e.id from group_payment_strategy e where e.code = 'CONDITIONAL');
update requirements_group set group_payment_strategy = 'FULL' where group_payment_strategy is null and group_payment_strategy_id = any(select e.id from group_payment_strategy e where e.code = 'FULL');
update requirements_group set group_payment_strategy = 'INAPPLICABLE' where group_payment_strategy is null and group_payment_strategy_id = any(select e.id from group_payment_strategy e where e.code = 'INAPPLICABLE');
update requirements_group set group_payment_strategy = 'PROPORTIONAL' where group_payment_strategy is null and group_payment_strategy_id = any(select e.id from group_payment_strategy e where e.code = 'PROPORTIONAL');
